3	const isNeighbor = (cell: Cell, other: Cell): boolean => {
4	  const [x, y] = cell;
5	  const [ox, oy] = other;
6	  const isSameCell = ox === x && oy === y;
7	  return !isSameCell && Math.abs(ox - x) <= 1 && Math.abs(oy - y) <= 1;
8	};
