const isLive = (cell: Cell, liveCells: Cell[]): boolean =>
  liveCells.some(([x, y]) => x === cell[0] && y === cell[1]);

const cellKey = (cell: Cell): string => `${cell[0]},${cell[1]}`;

export function nextGeneration(cells: Cell[]): Cell[] {
  const candidates: Cell[] = [];
  const seen = new Set<string>();
  for (const cell of cells) {
    const [x, y] = cell;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const candidate: Cell = [x + dx, y + dy];
        const key = cellKey(candidate);
        if (!seen.has(key)) {
          seen.add(key);
          candidates.push(candidate);
        }
      }
    }
  }
  return candidates.filter((cell) => {
    const neighborCount = countLiveNeighbors(cell, cells);
    if (isLive(cell, cells)) {
      return neighborCount === 2 || neighborCount === 3;
    }
    return neighborCount === 3;
  });
}

